 32→class PostListAdapter(
 33→    context: Context,
 34→    private val imageManager: ImageManager,
 35→    private val uiHelpers: UiHelpers
 36→) : PagedListAdapter<PostListItemType, ViewHolder>(PostListDiffItemCallback) {
 37→    private val layoutInflater: LayoutInflater = LayoutInflater.from(context)
 38→    private var itemLayoutType: PostListViewLayoutType = PostListViewLayoutType.defaultValue
 39→
 40→    override fun getItemViewType(position: Int): Int {
 41→        return when (getItem(position)) {
 42→            is EndListIndicatorItem -> VIEW_TYPE_ENDLIST_INDICATOR
 43→            is PostListItemUiState -> {
 44→                when (itemLayoutType) {
 45→                    STANDARD -> VIEW_TYPE_POST
 46→                    COMPACT -> VIEW_TYPE_POST_COMPACT
 47→                }
 48→            }
 49→            is LoadingItem, null -> {
 50→                when (itemLayoutType) {
 51→                    STANDARD -> VIEW_TYPE_LOADING
 52→                    COMPACT -> VIEW_TYPE_LOADING_COMPACT
 53→                }
 54→            }
 55→        }
 56→    }
 57→
 58→    @Suppress("UseCheckOrError")
 59→    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
 60→        return when (viewType) {
 61→            VIEW_TYPE_ENDLIST_INDICATOR -> {
 62→                val view = layoutInflater.inflate(R.layout.list_with_fab_endlist_indicator, parent, false)
 63→                EndListViewHolder(view)
 64→            }
 65→            VIEW_TYPE_LOADING -> {
 66→                val view = layoutInflater.inflate(R.layout.post_list_item_skeleton, parent, false)
 67→                LoadingViewHolder(view)
 68→            }
 69→            VIEW_TYPE_LOADING_COMPACT -> {
 70→                val view = layoutInflater.inflate(R.layout.post_list_item_skeleton_compact, parent, false)
 71→                LoadingViewHolder(view)
 72→            }
 73→            VIEW_TYPE_POST -> {
 74→                PostListItemViewHolder.Standard(parent, imageManager, uiHelpers)
 75→            }
 76→            VIEW_TYPE_POST_COMPACT -> {
 77→                PostListItemViewHolder.Compact(parent, imageManager, uiHelpers)
 78→            }
 79→            else -> {
 80→                // Fail fast if a new view type is added so the we can handle it
 81→                throw IllegalStateException("The view type '$viewType' needs to be handled")
 82→            }
 83→        }
 84→    }
 85→
 86→    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
 87→        // The only holders that require special setup are PostListItemViewHolder and LoadingViewHolder subclasses
 88→        if (holder is PostListItemViewHolder) {
 89→            val item = getItem(position)
 90→            assert(item is PostListItemUiState) {
 91→                "If we are presenting PostViewHolder, the item has to be of type PostListItemUiState " +
 92→                        "for position: $position"
 93→            }
 94→            holder.onBind((item as PostListItemUiState))
 95→        }
 96→        if (holder is LoadingViewHolder) {
 97→            val item = getItem(position)
 98→            assert(item is LoadingItem?) {
 99→                "If we are presenting LoadingViewHolder, the item has to be of type LoadingItem " +
100→                        "for position: $position"
101→            }
102→            // getItem returns the item, or NULL, if a null placeholder is at the specified position.
103→            item?.let { holder.onBind((item as LoadingItem)) }
104→        }
105→    }
